async (params, browser) => {
  // Open Trello
  await browser.open('https://trello.com')

  // Let Trello load
  await browser.wait(2000)

  // Move card via Trello API
  const result = await browser.evaluate(`const resp = await fetch('/1/cards/' + params.card_id + '?idList=' + params.target_list_id + '', { method: 'PUT', credentials: 'same-origin' }); if (!resp.ok) { const err = await resp.text(); throw new Error('Move failed: ' + resp.status + ' ' + err); } const card = await resp.json(); return { success: true, card_id: card.id, card_name: card.name, new_list_id: '' + params.target_list_id + '', url: card.shortUrl || card.url }`)

  return result
}
